 8→export function useUser() {
 9→  const [user, setUser] = useState<User | null>(null);
10→  const [profile, setProfile] = useState<Profile | null>(null);
11→  const [loading, setLoading] = useState(true);
12→  const supabase = createClient();
13→
14→  useEffect(() => {
15→    const getUser = async () => {
16→      const { data: { user } } = await supabase.auth.getUser();
17→      setUser(user);
18→
19→      if (user) {
20→        const { data } = await supabase
21→          .from('profiles')
22→          .select('*')
23→          .eq('id', user.id)
24→          .single();
25→        setProfile(data);
26→      }
27→
28→      setLoading(false);
29→    };
30→
31→    getUser();
32→
33→    const { data: { subscription } } = supabase.auth.onAuthStateChange(
34→      async (_event, session) => {
35→        setUser(session?.user ?? null);
36→        if (session?.user) {
37→          const { data } = await supabase
38→            .from('profiles')
39→            .select('*')
40→            .eq('id', session.user.id)
41→            .single();
42→          setProfile(data);
43→        } else {
44→          setProfile(null);
45→        }
46→      }
47→    );
48→
49→    return () => subscription.unsubscribe();
50→  }, []);
51→
52→  return { user, profile, loading };
