const { chromium } = require('playwright');
const path = require('path');
const fs = require('fs');

const SCREENSHOTS_DIR = path.resolve('C:/Users/User/nexus-ai/test-screenshots');
const BASE_URL = 'https://nexus-ai-silk-six.vercel.app';
const OUTPUT_FILE = path.join(SCREENSHOTS_DIR, 'debug-500.txt');

// Ensure screenshots directory exists
if (!fs.existsSync(SCREENSHOTS_DIR)) {
  fs.mkdirSync(SCREENSHOTS_DIR, { recursive: true });
}

// Collector for all findings
const findings = [];
function log(msg) {
  console.log(msg);
  findings.push(msg);
}

(async () => {
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: { width: 1280, height: 900 },
  });
  const page = await context.newPage();

  // ================================================================
  // Collectors for network requests, responses, and console messages
  // ================================================================
  const failedRequests = [];
  const allRequests = [];
  const consoleErrors = [];
  const pageErrors = [];

  // Capture ALL console messages
  page.on('console', msg => {
    const text = msg.text();
    const type = msg.type();
    if (type === 'error' || type === 'warning') {
      consoleErrors.push({ type, text, url: page.url() });
      log(`[CONSOLE ${type.toUpperCase()}] ${text}`);
    }
  });

  // Capture uncaught page errors
  page.on('pageerror', err => {
    pageErrors.push({ message: err.message, stack: err.stack, url: page.url() });
    log(`[PAGE ERROR] ${err.message}`);
  });

  // Capture ALL network requests and responses
  page.on('response', async (response) => {
    const url = response.url();
    const status = response.status();
    const method = response.request().method();

    const entry = {
      url,
      status,
      method,
      statusText: response.statusText(),
    };

    allRequests.push(entry);

    // Capture details for any 4xx or 5xx response
    if (status >= 400) {
      let body = '';
      try {
        body = await response.text();
      } catch (e) {
        body = `[Could not read body: ${e.message}]`;
      }

      const headers = {};
      try {
        const allHeaders = await response.allHeaders();
        for (const [key, value] of Object.entries(allHeaders)) {
          headers[key] = value;
        }
      } catch (e) {
        // ignore
      }

      const failedEntry = {
        ...entry,
        body: body.substring(0, 5000), // limit to 5000 chars
        responseHeaders: headers,
        requestHeaders: response.request().headers(),
        postData: response.request().postData() || null,
      };

      failedRequests.push(failedEntry);
      log(`\n[FAILED REQUEST] ${method} ${url}`);
      log(`  Status: ${status} ${response.statusText()}`);
      log(`  Response Body: ${body.substring(0, 2000)}`);
    }
  });

  // Also capture request failures (network errors, DNS failures, etc.)
  page.on('requestfailed', request => {
    const failure = request.failure();
    const url = request.url();
    const method = request.method();
    log(`[REQUEST FAILED] ${method} ${url} - ${failure?.errorText || 'Unknown error'}`);
    failedRequests.push({
      url,
      method,
      status: 0,
      statusText: 'REQUEST_FAILED',
      body: failure?.errorText || 'Unknown error',
      requestHeaders: request.headers(),
    });
  });

  try {
    // ============================================================
    // PHASE 1: LOGIN
    // ============================================================
    log('\n' + '='.repeat(80));
    log('PHASE 1: Navigate to Login Page');
    log('='.repeat(80));

    const loginResponse = await page.goto(`${BASE_URL}/login`, {
      waitUntil: 'networkidle',
      timeout: 30000,
    });
    log(`Login page status: ${loginResponse.status()}`);
    log(`Login page URL: ${page.url()}`);

    await page.screenshot({
      path: path.join(SCREENSHOTS_DIR, 'debug-01-login-page.png'),
      fullPage: true,
    });

    // Fill email
    log('\nFilling login form...');
    try {
      const emailSelector = 'input[name="email"], input[type="email"], input[placeholder*="email" i], input[id*="email" i]';
      await page.waitForSelector(emailSelector, { timeout: 5000 });
      await page.fill(emailSelector, 'testuser@nexusai-test.com');
      log('Filled Email: "testuser@nexusai-test.com"');
    } catch (e) {
      log(`Could not fill email field: ${e.message}`);
    }

    // Fill password
    try {
      const passwordSelector = 'input[name="password"], input[type="password"], input[placeholder*="password" i], input[id*="password" i]';
      await page.waitForSelector(passwordSelector, { timeout: 5000 });
      await page.fill(passwordSelector, 'TestPassword123!');
      log('Filled Password: "TestPassword123!"');
    } catch (e) {
      log(`Could not fill password field: ${e.message}`);
    }

    await page.screenshot({
      path: path.join(SCREENSHOTS_DIR, 'debug-02-login-filled.png'),
      fullPage: true,
    });

    // ============================================================
    // PHASE 2: CLICK LOGIN AND CAPTURE ALL NETWORK DURING TRANSITION
    // ============================================================
    log('\n' + '='.repeat(80));
    log('PHASE 2: Click Login and capture network traffic');
    log('='.repeat(80));

    // Clear previous requests to focus on login+dashboard requests
    const preLoginRequestCount = allRequests.length;

    // Click sign in
    try {
      const signInBtn = page.locator('button:has-text("Sign in"), button:has-text("Log in"), button:has-text("Login"), button[type="submit"]').first();
      await signInBtn.click();
      log('Clicked Sign In button');

      // Wait for navigation to /dashboard
      try {
        await page.waitForURL('**/dashboard**', { timeout: 15000 });
        log(`Successfully navigated to: ${page.url()}`);
      } catch (e) {
        log(`Navigation timeout. Current URL: ${page.url()}`);
        // Check if we're still on login
        const currentUrl = page.url();
        if (currentUrl.includes('/login')) {
          log('STILL ON LOGIN PAGE - login may have failed');

          // Check for error messages
          const messages = await page.evaluate(() => {
            const alerts = document.querySelectorAll('[role="alert"], .error, .alert, .toast, [class*="error"], [class*="alert"], [class*="toast"]');
            return Array.from(alerts).map(el => el.textContent?.trim()).filter(Boolean);
          });
          if (messages.length > 0) {
            log('Error messages on login page: ' + JSON.stringify(messages, null, 2));
          }
        }
      }
    } catch (e) {
      log(`Could not click Sign In: ${e.message}`);
    }

    await page.screenshot({
      path: path.join(SCREENSHOTS_DIR, 'debug-03-after-login-click.png'),
      fullPage: true,
    });

    // ============================================================
    // PHASE 3: WAIT FOR DASHBOARD TO FULLY LOAD
    // ============================================================
    log('\n' + '='.repeat(80));
    log('PHASE 3: Wait for dashboard to fully load');
    log('='.repeat(80));

    // Wait additional time for all API calls to complete
    log('Waiting for network to settle...');
    try {
      await page.waitForLoadState('networkidle', { timeout: 15000 });
      log('Network is idle');
    } catch (e) {
      log(`Network did not settle: ${e.message}`);
    }

    // Additional wait for any delayed requests
    await page.waitForTimeout(5000);

    const currentUrl = page.url();
    log(`Current URL after dashboard load: ${currentUrl}`);

    await page.screenshot({
      path: path.join(SCREENSHOTS_DIR, 'debug-04-dashboard-loaded.png'),
      fullPage: true,
    });

    // ============================================================
    // PHASE 4: CHECK WHAT'S ON THE DASHBOARD PAGE
    // ============================================================
    log('\n' + '='.repeat(80));
    log('PHASE 4: Inspect dashboard page content');
    log('='.repeat(80));

    const pageContent = await page.evaluate(() => {
      return {
        title: document.title,
        h1: Array.from(document.querySelectorAll('h1')).map(el => el.textContent?.trim()),
        h2: Array.from(document.querySelectorAll('h2')).map(el => el.textContent?.trim()),
        errors: Array.from(document.querySelectorAll('[role="alert"], .error, [class*="error"]')).map(el => el.textContent?.trim()),
        bodyText: document.body?.innerText?.substring(0, 3000),
      };
    });
    log(`Page title: ${pageContent.title}`);
    log(`H1 elements: ${JSON.stringify(pageContent.h1)}`);
    log(`H2 elements: ${JSON.stringify(pageContent.h2)}`);
    if (pageContent.errors.length > 0) {
      log(`Error elements: ${JSON.stringify(pageContent.errors)}`);
    }
    log(`Page body text (first 3000 chars):\n${pageContent.bodyText}`);

    // ============================================================
    // PHASE 5: NAVIGATE DIRECTLY TO DASHBOARD TO TRIGGER FRESH LOAD
    // ============================================================
    log('\n' + '='.repeat(80));
    log('PHASE 5: Direct navigation to /dashboard (fresh load)');
    log('='.repeat(80));

    const dashboardPreNavigateFailedCount = failedRequests.length;

    const dashResponse = await page.goto(`${BASE_URL}/dashboard`, {
      waitUntil: 'networkidle',
      timeout: 30000,
    });
    log(`Dashboard direct navigation status: ${dashResponse ? dashResponse.status() : 'null'}`);
    log(`Dashboard URL after navigation: ${page.url()}`);

    // Wait for any additional XHR/fetch calls
    await page.waitForTimeout(5000);

    await page.screenshot({
      path: path.join(SCREENSHOTS_DIR, 'debug-05-dashboard-direct.png'),
      fullPage: true,
    });

    // Check if we got redirected back to login
    if (page.url().includes('/login')) {
      log('WARNING: Redirected back to /login - session may not be valid');
    }

    // ============================================================
    // PHASE 6: TRY OTHER DASHBOARD PAGES THAT MAKE API CALLS
    // ============================================================
    log('\n' + '='.repeat(80));
    log('PHASE 6: Check other dashboard sub-pages');
    log('='.repeat(80));

    const subPages = [
      '/dashboard/documents',
      '/dashboard/surveys',
      '/dashboard/settings',
      '/dashboard/templates',
    ];

    for (const subPage of subPages) {
      log(`\n--- Navigating to ${subPage} ---`);
      try {
        const resp = await page.goto(`${BASE_URL}${subPage}`, {
          waitUntil: 'networkidle',
          timeout: 20000,
        });
        log(`  Status: ${resp ? resp.status() : 'null'}`);
        log(`  URL: ${page.url()}`);
        await page.waitForTimeout(3000);
      } catch (e) {
        log(`  Error navigating to ${subPage}: ${e.message}`);
      }
    }

    await page.screenshot({
      path: path.join(SCREENSHOTS_DIR, 'debug-06-subpages.png'),
      fullPage: true,
    });

    // ============================================================
    // PHASE 7: DIRECTLY HIT API ENDPOINTS
    // ============================================================
    log('\n' + '='.repeat(80));
    log('PHASE 7: Direct API endpoint tests');
    log('='.repeat(80));

    const apiEndpoints = [
      '/api/health',
      '/api/surveys',
      '/api/documents/upload',
    ];

    for (const endpoint of apiEndpoints) {
      log(`\n--- Testing API: ${endpoint} ---`);
      try {
        const resp = await page.goto(`${BASE_URL}${endpoint}`, {
          waitUntil: 'networkidle',
          timeout: 15000,
        });
        log(`  Status: ${resp ? resp.status() : 'null'}`);
        let body = '';
        try {
          body = await resp.text();
        } catch(e) {
          body = '[could not read]';
        }
        log(`  Body: ${body.substring(0, 2000)}`);
      } catch (e) {
        log(`  Error: ${e.message}`);
      }
    }

    // ============================================================
    // SUMMARY
    // ============================================================
    log('\n' + '='.repeat(80));
    log('SUMMARY OF ALL FINDINGS');
    log('='.repeat(80));

    log(`\n--- Total network requests captured: ${allRequests.length} ---`);
    log(`--- Total FAILED requests (4xx/5xx): ${failedRequests.length} ---`);
    log(`--- Total console errors: ${consoleErrors.length} ---`);
    log(`--- Total page errors: ${pageErrors.length} ---`);

    if (failedRequests.length > 0) {
      log('\n\n========== DETAILED FAILED REQUESTS ==========');
      failedRequests.forEach((req, i) => {
        log(`\n--- Failed Request #${i + 1} ---`);
        log(`  Method: ${req.method}`);
        log(`  URL: ${req.url}`);
        log(`  Status: ${req.status} ${req.statusText}`);
        if (req.postData) {
          log(`  Post Data: ${req.postData.substring(0, 1000)}`);
        }
        if (req.body) {
          log(`  Response Body: ${req.body.substring(0, 3000)}`);
        }
        if (req.responseHeaders) {
          log(`  Response Headers: ${JSON.stringify(req.responseHeaders, null, 2)}`);
        }
      });
    }

    if (consoleErrors.length > 0) {
      log('\n\n========== CONSOLE ERRORS ==========');
      consoleErrors.forEach((err, i) => {
        log(`\n--- Console Error #${i + 1} ---`);
        log(`  Type: ${err.type}`);
        log(`  Text: ${err.text}`);
        log(`  Page URL: ${err.url}`);
      });
    }

    if (pageErrors.length > 0) {
      log('\n\n========== PAGE ERRORS ==========');
      pageErrors.forEach((err, i) => {
        log(`\n--- Page Error #${i + 1} ---`);
        log(`  Message: ${err.message}`);
        log(`  Stack: ${err.stack}`);
        log(`  Page URL: ${err.url}`);
      });
    }

    // List all requests with their status codes
    log('\n\n========== ALL NETWORK REQUESTS (sorted by status) ==========');
    const sortedRequests = [...allRequests].sort((a, b) => b.status - a.status);
    sortedRequests.forEach((req) => {
      const marker = req.status >= 400 ? '*** FAIL ***' : '    OK     ';
      log(`  [${marker}] ${req.status} ${req.method} ${req.url}`);
    });

  } catch (error) {
    log(`\n!!! FATAL ERROR: ${error.message}`);
    log(`Stack: ${error.stack}`);
    try {
      await page.screenshot({
        path: path.join(SCREENSHOTS_DIR, 'debug-error-screenshot.png'),
        fullPage: true,
      });
    } catch(e) {
      // ignore screenshot error
    }
  } finally {
    // Write all findings to file
    const output = findings.join('\n');
    fs.writeFileSync(OUTPUT_FILE, output, 'utf-8');
    log(`\nAll findings saved to: ${OUTPUT_FILE}`);

    await browser.close();
  }
})();

